// Move every selected token's Phase of Night marker one step forward
// (wraps at the end of the night). Posts a single chat message listing
// every affected actor and the phase they ended up in.
const tokens = canvas.tokens?.controlled ?? [];
if (!tokens.length) {
  ui.notifications.warn("Select at least one token first.");
  return;
}
const LABELS = (CONFIG.MTA && CONFIG.MTA.phaseOfNightLabels) || [];
const moved = [];
for (const token of tokens) {
  const actor = token.actor;
  if (!actor) continue;
  if (typeof actor.advancePhaseOfNight === "function") {
    await actor.advancePhaseOfNight(1);
  } else {
    const cur = Number(actor.system?.phaseOfNight ?? 0) || 0;
    const next = (((cur + 1) % 10) + 10) % 10;
    await actor.update({ "system.phaseOfNight": next });
  }
  const phaseIdx = Math.max(0, Math.min(9, Math.floor(Number(actor.system?.phaseOfNight ?? 0) || 0)));
  moved.push({ name: actor.name, label: LABELS[phaseIdx] ?? `Phase ${phaseIdx}` });
}
if (moved.length) {
  const list = moved.map(m => `<li><strong>${m.name}</strong> &mdash; ${m.label}</li>`).join("");
  await ChatMessage.create({
    user: game.user.id,
    speaker: { alias: "Storyteller" },
    content: `<p>Your Storyteller moved the clock forward for&hellip;</p><ul>${list}</ul>`
  });
}
